sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    // implement resource here
	taskId + '/getDurationInformation';
	var taskId = request.pathParams.taskId;
	var durationInformation = _durationInformation(taskId);
	response.setBody({
		task: taskId,
		durationInformation: durationInformation
	});

	response.setStatus(200);
	response.setContentType('application/json');

	function _durationInformation(taskId){
		var lDurationInfo = {};
		var gr_task = new GlideRecordSecure("x_153465_discovert_route_task_instance");

		if(gr_task.get(taskId)){
			lDurationInfo.taskId = taskId;
			lDurationInfo["task_order"] = _getFieldObject(gr_task, "task_order");
			// NOTE: warning hours is actually a number of days, not hours
			lDurationInfo["warning_hours"] = _getFieldObject(gr_task, "warning_hours");
			lDurationInfo["expected_start"] = _getFieldObject(gr_task, "expected_start");
			// NOTE: this is Estimated Effort
			lDurationInfo["calendar_duration"] = _getFieldObject(gr_task, "calendar_duration");
			lDurationInfo["u_wait_for_subtasks_to_finish"] = _getFieldObject(gr_task, "u_wait_for_subtasks_to_finish");
			lDurationInfo["work_start"] = _getFieldObject(gr_task, "work_start");
			lDurationInfo["work_end"] = _getFieldObject(gr_task, "work_end");
			var outbound = gr_task.getValue("outbound");
			if(outbound==true){
				lDurationInfo["outbound"] = _getFieldObject(gr_task, "outbound");
				lDurationInfo["u_external_due_date"] = _getFieldObject(gr_task, "u_external_due_date");
			}
		}
		return lDurationInfo;
	}

	function _getFieldObject(gr_task, field){
		var fieldObject = {};
			fieldObject.label = _getFieldLabel(gr_task, field);
			fieldObject.value = gr_task.getValue(field);
			fieldObject.display_value = gr_task.getDisplayValue(field);
		return fieldObject;
	}

	function _getFieldLabel(gr_task, field){
		var elementLabel = field + " label - not found";
		var elements=gr_task.getElements();
		// For scope ,loop through array
		for(var i=0;i<elements.length;i++){
			var element=elements[i];
			var elementName = element.getName();
			if(elementName ==field){
				elementLabel = element.getLabel();
				break;
			}
		}
		return elementLabel;
	}

})(request, response);
